// ── Main ─────────────────────────────────────────────────────
export async function initF1({ trackType = 'none', teamId = '', driverId = '' } = {}) {
  console.log('[F1] initF1', { trackType, teamId, driverId });
  const contentEl = document.getElementById('f1-content');
  const errorEl   = document.getElementById('f1-error');

  try {
    const rankingFetch =
      trackType === 'team'   ? getTeamRanking(teamId) :
      trackType === 'driver' ? getDriverRanking(driverId) :
      null;

    const [nextRace, ranking] = await Promise.all([getNextRace(), rankingFetch]);
    console.log('[F1] ranking:', ranking);

    render(nextRace, ranking);
    contentEl.classList.remove('hidden');
    errorEl.classList.add('hidden');
  } catch {
    contentEl.classList.add('hidden');
    errorEl.classList.remove('hidden');
    errorEl.textContent = 'F1 資料無法載入';
  }
}

// ── Data fetching ─────────────────────────────────────────────
async function getNextRace() {
  const cached = loadCache(CACHE_SCHEDULE);
  if (cached) return cached;

  const res  = await fetch(`${BASE}/current.json`);
  const data = await res.json();
  const races = data?.MRData?.RaceTable?.Races ?? [];
  const now   = Date.now();

  const next = races.find(r =>
    new Date(`${r.date}T${r.time ?? '15:00:00Z'}`).getTime() > now
  ) ?? races[races.length - 1];

  const sessions = [];
  const addSession = (label, obj) => {
    if (obj?.date && obj?.time)
      sessions.push({ label, ts: new Date(`${obj.date}T${obj.time}`).getTime() });
  };
  addSession('FP1',  next.FirstPractice);
  addSession('FP2',  next.SecondPractice);
  if (next.ThirdPractice)      addSession('FP3',   next.ThirdPractice);
  if (next.SprintShootout)     addSession('SQ',    next.SprintShootout);
  if (next.SprintQualifying)   addSession('SQ',    next.SprintQualifying);
  if (next.Sprint)             addSession('Sprint', next.Sprint);
  addSession('Qual', next.Qualifying);
  addSession('Race', { date: next.date, time: next.time ?? '15:00:00Z' });

  const result = {
    name:      next.raceName,
    circuit:   next.Circuit.circuitName,
    circuitId: next.Circuit.circuitId,
    country:   next.Circuit.Location.country,
    date:      next.date,
    time:      next.time ?? '15:00:00Z',
    sessions,
  };

  saveCache(CACHE_SCHEDULE, result);
  return result;
}

async function getTeamRanking(teamId) {
  const key    = `${CACHE_STANDINGS}_team_${teamId}`;
  const cached = loadCache(key);
  if (cached) return cached;

  const res  = await fetch(`${BASE}/current/constructorStandings.json`);
  const data = await res.json();
  const standings = data?.MRData?.StandingsTable?.StandingsLists?.[0]?.ConstructorStandings ?? [];
  console.log('[F1] constructor IDs:', standings.map(s => s.Constructor.constructorId));
  const entry = standings.find(s => s.Constructor.constructorId === teamId);
  if (!entry) return null;

  const result = { pos: entry.position, pts: entry.points, label: entry.Constructor.name };
  saveCache(key, result);
  return result;
}

async function getDriverRanking(driverId) {
  const key    = `${CACHE_STANDINGS}_driver_${driverId}`;
  const cached = loadCache(key);
  if (cached) return cached;

  const res  = await fetch(`${BASE}/current/driverStandings.json`);
  const data = await res.json();
  const standings = data?.MRData?.StandingsTable?.StandingsLists?.[0]?.DriverStandings ?? [];
  const entry = standings.find(s => s.Driver.driverId === driverId);
  if (!entry) return null;

  const code = entry.Driver.code ?? entry.Driver.driverId.slice(0, 3).toUpperCase();
  const result = { pos: entry.position, pts: entry.points, label: code };
  saveCache(key, result);
  return result;
}

// ── Render ────────────────────────────────────────────────────
function render(race, ranking) {
  // 國旗
  const flagEl = document.getElementById('f1-flag');
  const iso = COUNTRY_FLAGS[race.country];
  if (iso) {
    flagEl.innerHTML = `<img src="https://flagcdn.com/w40/${iso}.png" alt="${race.country}">`;
  } else {
    flagEl.textContent = '🏁';
  }

  // 賽事名稱（去掉 Grand Prix 縮短）
  const shortName = race.name.replace(' Grand Prix', ' GP');
  document.getElementById('f1-race-name').textContent = shortName;

  // 倒數
  const raceTime = new Date(`${race.date}T${race.time}`);
  const diffMs   = raceTime - Date.now();
  const diffDays = Math.ceil(diffMs / 86400000);
  const countdownEl = document.getElementById('f1-countdown');
  if (diffMs <= 0)       countdownEl.textContent = '進行中';
  else if (diffDays <= 0) countdownEl.textContent = '今天開賽';
  else if (diffDays === 1) countdownEl.textContent = '明天開賽';
  else                   countdownEl.textContent = `${diffDays} 天後`;

  // 排名（2x1+）
  if (ranking) {
    document.getElementById('f1-rank-pos').textContent = `${ranking.label}  P${ranking.pos}`;
    document.getElementById('f1-rank-pts').textContent = `${ranking.pts} pts`;
    document.getElementById('f1-ranking').classList.remove('hidden');
  }

  // 賽道
  const path = CIRCUIT_PATHS[race.circuitId];
  if (path) {
    document.getElementById('f1-circuit-path').setAttribute('d', path);
    document.getElementById('f1-circuit-name').textContent = race.circuit;
    document.getElementById('f1-circuit-panel').classList.remove('hidden');
  }

  // 週末賽程（2x2 / 3x2）
  if (race.sessions?.length) {
    const now = Date.now();
    const fmt = ts => {
      const d = new Date(ts);
      const day = ['日','一','二','三','四','五','六'][d.getDay()];
      const hh  = String(d.getHours()).padStart(2, '0');
      const mm  = String(d.getMinutes()).padStart(2, '0');
      return { day, time: `${hh}:${mm}` };
    };
    const list = document.getElementById('f1-schedule-list');
    list.innerHTML = race.sessions.map(s => {
      const { day, time } = fmt(s.ts);
      const past = s.ts < now;
      return `<div class="f1-session${past ? ' f1-session-past' : ''}">
        <span class="f1-session-label">${s.label}</span>
        <span class="f1-session-day">週${day}</span>
        <span class="f1-session-time">${time}</span>
      </div>`;
    }).join('');
    document.getElementById('f1-schedule').classList.remove('hidden');
  }
}

// ── Cache ─────────────────────────────────────────────────────
function loadCache(key) {
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return null;
    const { data, ts } = JSON.parse(raw);
    if (Date.now() - ts > CACHE_TTL) return null;
    return data;
  } catch { return null; }
}

function saveCache(key, data) {
  try { localStorage.setItem(key, JSON.stringify({ data, ts: Date.now() })); } catch {}
}

